SELECT MAX(total_stakes) AS highest_total_bets
FROM (
  SELECT user_id, SUM(stake) AS total_stakes
  FROM bets
  GROUP BY user_id
);

SELECT SUM(u.profit) AS total_profit
FROM users u
WHERE u.user_id IN (
  SELECT b.user_id
  FROM bets b
  WHERE b.bet_date = (
    SELECT MAX(bet_date)
    FROM bets
  )
);
